361→                        if (uiState.currentSentence.isNotBlank()) {
362→                            Spacer(Modifier.height(8.dp))
363→                            Row(
364→                                modifier = Modifier.fillMaxWidth(),
365→                                horizontalArrangement = Arrangement.spacedBy(8.dp)
366→                            ) {
