508→                IconButton(onClick = {
509→                    onFavorite()
510→                    isFavorited = !isFavorited
511→                }) {
512→                    Icon(
513→                        if (isFavorited) Icons.Default.Favorite else Icons.Default.FavoriteBorder,
514→                        "收藏",
515→                        tint = if (isFavorited) Color(0xFFF44336) else MaterialTheme.colorScheme.onSurfaceVariant
516→                    )
517→                }
518→                IconButton(onClick = onDismiss) { Icon(Icons.Default.Close, "关闭") }
519→            }
520→            Text(card.translation, style = MaterialTheme.typography.bodyLarge, color = MaterialTheme.colorScheme.primary)
521→            if (card.definitions.isNotEmpty()) {
522→                Spacer(Modifier.height(8.dp))
523→                Text("📖 释义", style = MaterialTheme.typography.labelMedium)
524→                card.definitions.forEach { def ->
525→                    Text("${def.partOfSpeech} ${def.definition}", style = MaterialTheme.typography.bodySmall)
526→                }
527→            }
528→            if (card.examples.isNotEmpty()) {
529→                Spacer(Modifier.height(8.dp))
530→                Text("💬 例句", style = MaterialTheme.typography.labelMedium)
531→                card.examples.forEach { ex ->
532→                    Text(ex, style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
533→                }
