                    "spanish", "es" -> "es"
                    "french", "fr" -> "fr"
                    "german", "de" -> "de"
                    "italian", "it" -> "it"
                    "portuguese", "pt" -> "pt"
                    "russian", "ru" -> "ru"
                    "japanese", "ja" -> "ja"
                    "korean", "ko" -> "ko"
                    "arabic", "ar" -> "ar"
                    "hindi", "hi" -> "hi"
                    "thai", "th" -> "th"
                    "vietnamese", "vi" -> "vi"
