data class PlayerUiState(
    val subtitles: List<SubtitleCue> = emptyList(),
    val wordTimings: List<WordTimestamp> = emptyList(),
    val currentCueIndex: Int = -1,
    val currentPositionMs: Long = 0,
    val mode: String = "learn", // "learn" or "dictation"
    val currentLang: String = "en",
    val statusText: String = "加载中...",
    val isTranscribing: Boolean = false,
    // Transcription progress (for segmented transcription)
    val transcribeSegment: Int = 0,
    val transcribeTotalSegments: Int = 0,
    val transcribeProgress: Int = 0,
    val transcribeRemainingSeconds: Long = 0,
    // Word card
    val showWordCard: Boolean = false,
    val wordCardData: WordCardData? = null,
    val currentSentence: String = "",
    // AI analysis
    val aiAnalysisResult: String? = null,
    val isAnalyzing: Boolean = false,
    // Dictation
    val dictationIndex: Int = 0,
    // AI 验证
    val showAiValidation: Boolean = false,
    val aiValidationResult: String? = null,
    val isValidating: Boolean = false
)

@HiltViewModel
class PlayerViewModel @Inject constructor(
    application: Application,
    private val favoriteRepository: FavoriteRepository,
    private val aiConfigStore: AIConfigStore,
    private val aiService: AIService,
    private val dictionaryService: DictionaryService,
    private val ffmpegSegmentedService: FFmpegSegmentedTranscriptionService
) : AndroidViewModel(application) {

    private val _uiState = MutableStateFlow(PlayerUiState())
    val uiState: StateFlow<PlayerUiState> = _uiState.asStateFlow()

    private var tts: TextToSpeech? = null
    private val json = Json { ignoreUnknownKeys = true }

    init {
        tts = TextToSpeech(application) { status ->
            if (status == TextToSpeech.SUCCESS) {
                tts?.language = Locale.US
            }
        }
    }

    fun loadSubtitles(videoPath: String, subtitlePath: String?) {
        viewModelScope.launch(Dispatchers.IO) {
            // Try loading VTT subtitle
            val vttPath = subtitlePath ?: findExistingSubtitle(videoPath)
            if (vttPath != null) {
                val file = File(vttPath)
                if (file.exists()) {
                    val content = file.readText()
                    val subs = VttParser.parse(content)
                    if (subs.isNotEmpty()) {
                        _uiState.update { it.copy(
                            subtitles = subs,
                            statusText = "已加载 ${subs.size} 条字幕"
                        )}
                        // Load word timestamps if available
                        loadWordTimestamps(vttPath)
                        return@launch
                    }
                }
            }
            _uiState.update { it.copy(statusText = "无字幕文件，请在 AI 设置中配置 Groq Whisper 后重新转录") }
        }
    }

    private fun findExistingSubtitle(videoPath: String): String? {
        val base = videoPath.substringBeforeLast(".")
        for (ext in listOf(".vtt", ".srt")) {
            val f = File(base + ext)
            if (f.exists()) return f.absolutePath
        }
        // Check with language suffix
        val dir = File(videoPath).parentFile ?: return null
        val name = File(videoPath).nameWithoutExtension
        dir.listFiles()?.forEach { f ->
            if (f.name.startsWith(name) && f.extension == "vtt") return f.absolutePath
        }
        return null
    }

    private fun loadWordTimestamps(vttPath: String) {
        val wtsPath = vttPath.replace(Regex("\\.vtt$"), ".wordts.json")
        val wtsFile = File(wtsPath)
        if (wtsFile.exists()) {
            try {
                val timings: List<WordTimestamp> = json.decodeFromString(wtsFile.readText())
                _uiState.update { it.copy(wordTimings = timings) }
            } catch (_: Exception) {}
        }
    }

    /** Called every 30ms from the player to sync subtitles */
    fun updatePosition(positionMs: Long) {
        _uiState.update { it.copy(currentPositionMs = positionMs) }
        val subs = _uiState.value.subtitles
        if (subs.isEmpty()) return

        // Binary search for current cue (ported from renderer.js)
        var lo = 0; var hi = subs.size - 1; var idx = -1
        while (lo <= hi) {
            val mid = (lo + hi) ushr 1
            when {
                positionMs < subs[mid].startMs -> hi = mid - 1
                positionMs > subs[mid].endMs -> lo = mid + 1
                else -> { idx = mid; break }
            }
        }
        // Gap handling: find next cue within 0.5s
        if (idx < 0) {
            for (i in subs.indices) {
                if (subs[i].startMs > positionMs) {
                    idx = if (subs[i].startMs - positionMs < 500) i else if (i > 0) i - 1 else 0
                    break
                }
            }
            if (idx < 0) idx = subs.size - 1
        }

        if (idx != _uiState.value.currentCueIndex) {
            _uiState.update { it.copy(
                currentCueIndex = idx,
                currentSentence = subs[idx].text,
                showWordCard = false,
                aiAnalysisResult = null
            )}
        }
    }

    /** Retranscribe - 使用前台服务支持后台转录 */
    fun retranscribe(videoPath: String) {
        val context = getApplication<Application>()
        val videoName = File(videoPath).nameWithoutExtension

        // 保存旧字幕状态
        val oldSubtitles = _uiState.value.subtitles
        val oldWordTimings = _uiState.value.wordTimings

        _uiState.update { it.copy(
            subtitles = emptyList(),
            wordTimings = emptyList(),
            currentCueIndex = -1,
            isTranscribing = true,
            transcribeSegment = 0,
            transcribeTotalSegments = 0,
            transcribeProgress = 0,
            statusText = "正在准备转录..."
        )}

        // 启动前台服务进行转录
        val intent = Intent(context, TranscriptionService::class.java).apply {
            action = TranscriptionService.ACTION_START
            putExtra(TranscriptionService.EXTRA_VIDEO_PATH, videoPath)
            putExtra(TranscriptionService.EXTRA_VIDEO_NAME, videoName)
        }
        context.startForegroundService(intent)

        // 保存旧字幕以备失败时恢复
        _oldSubtitles = oldSubtitles
        _oldWordTimings = oldWordTimings
    }

    // 用于保存旧字幕的临时变量
    private var _oldSubtitles: List<SubtitleCue> = emptyList()
    private var _oldWordTimings: List<WordTimestamp> = emptyList()

    /**
     * 取消转录
     */
    fun cancelTranscription(context: Context) {
        val intent = Intent(context, TranscriptionService::class.java).apply {
            action = TranscriptionService.ACTION_CANCEL
        }
        context.startService(intent)

        // 重置 UI 状态
        _uiState.update { it.copy(
            isTranscribing = false,
            transcribeSegment = 0,
            transcribeTotalSegments = 0,
            transcribeProgress = 0,
            transcribeRemainingSeconds = 0,
            statusText = "转录已取消"
        )}
    }

    /**
     * 处理服务发送的进度更新
     */
    fun onTranscriptionProgress(segment: Int, total: Int, progress: Int, message: String, remaining: Long) {
        val remainingText = if (remaining > 0) {
            "剩余 ${formatRemainingTime(remaining)}"
        } else {
            ""
        }
        _uiState.update { it.copy(
            transcribeSegment = segment,
            transcribeTotalSegments = total,
            transcribeProgress = progress,
            transcribeRemainingSeconds = remaining,
            statusText = if (total > 1) {
                "分段转录: $segment/$total 段 ($progress%)\n$message\n$remainingText"
            } else {
                "$message\n$remainingText"
            }
        )}
    }

    /**
     * 处理转录完成
     */
    /**
     * 处理转录完成
     * 支持大模型交叉验证
     */
    fun onTranscriptionCompleted(videoPath: String, success: Boolean, detectedLang: String, subtitleCount: Int, error: String?) {
        if (success) {
            // 重新加载字幕文件
            loadSubtitles(videoPath, null)
            // 自动切换 UI 语言到检测到的语言
