    /** Look up a word - ported from renderer.js showWordInline() */
    fun lookupWord(word: String) {
        _uiState.update { it.copy(showWordCard = true, wordCardData = WordCardData(word = word, translation = "查询中...")) }
        speak(word)

        viewModelScope.launch(Dispatchers.IO) {
            val lang = _uiState.value.currentLang
            val context = _uiState.value.currentSentence
            val aiConfig = aiConfigStore.config.first()

            // 渐进式查词：先显示快速结果，再补充详细信息
            when (lang) {
                "en" -> {
                    val onlineDeferred = async { runCatching { dictionaryService.lookupEnglish(word) }.getOrNull() }
                    val transDeferred = async { runCatching { dictionaryService.translate(word, "en") }.getOrNull() }
                    val aiDeferred = async { runCatching { aiTranslateWord(word, context, lang, aiConfig) }.getOrNull() }

                    // 任何一个先返回就更新
                    val trans = transDeferred.await()
                    if (trans != null) {
                        _uiState.update { it.copy(wordCardData = WordCardData(word = word, translation = trans)) }
                    }

                    val online = onlineDeferred.await()
                    if (online != null) {
                        _uiState.update { it.copy(wordCardData = WordCardData(
                            word = word,
                            phonetic = online.phonetic,
                            translation = trans ?: online.translation,
                            definitions = online.definitions,
                            examples = online.examples
                        )) }
                    }

                    val aiTrans = aiDeferred.await()
                    val currentCard = _uiState.value.wordCardData
                    _uiState.update { it.copy(wordCardData = WordCardData(
                        word = word,
                        phonetic = currentCard?.phonetic ?: online?.phonetic ?: "",
                        translation = aiTrans ?: currentCard?.translation ?: trans ?: "未找到释义",
                        definitions = currentCard?.definitions ?: online?.definitions ?: emptyList(),
                        examples = currentCard?.examples ?: online?.examples ?: emptyList()
                    )) }
                }
                "ja" -> {
                    val onlineDeferred = async { runCatching { dictionaryService.lookupJapanese(word) }.getOrNull() }
                    val transDeferred = async { runCatching { dictionaryService.translate(word, "ja") }.getOrNull() }
                    val aiDeferred = async { runCatching { aiTranslateWord(word, context, lang, aiConfig) }.getOrNull() }

                    val trans = transDeferred.await()
                    if (trans != null) {
                        _uiState.update { it.copy(wordCardData = WordCardData(word = word, translation = trans)) }
                    }

                    val online = onlineDeferred.await()
                    val aiTrans = aiDeferred.await()
                    _uiState.update { it.copy(wordCardData = WordCardData(
                        word = word,
                        phonetic = online?.phonetic ?: "",
                        translation = aiTrans ?: trans ?: "未找到释义",
                        definitions = online?.definitions ?: emptyList()
                    )) }
                }
                else -> {
                    val transDeferred = async { runCatching { dictionaryService.translate(word, lang) }.getOrNull() }
                    val aiDeferred = async { runCatching { aiTranslateWord(word, context, lang, aiConfig) }.getOrNull() }

                    val trans = transDeferred.await()
                    if (trans != null) {
                        _uiState.update { it.copy(wordCardData = WordCardData(word = word, translation = trans)) }
                    }

                    val aiTrans = aiDeferred.await()
                    _uiState.update { it.copy(wordCardData = WordCardData(
                        word = word,
                        translation = aiTrans ?: trans ?: "未找到释义"
                    )) }
                }
            }
        }
    }

    private suspend fun aiTranslateWord(word: String, context: String, lang: String, config: AIConfig): String? {
        val langName = LANGUAGES.find { it.code == lang }?.name ?: "英语"
        val prompt = "将${langName}「${word}」翻译为中文。${if (context.isNotBlank()) "语境:\"$context\"。" else ""}只回复中文释义，多义项用/分隔，不要音译。"
        return aiService.chat(config, prompt)
    }

    fun hideWordCard() { _uiState.update { it.copy(showWordCard = false) } }

    /** AI analyze sentence - 增强版 */
    fun analyzeSentence() {
        val sentence = _uiState.value.currentSentence
        if (sentence.isBlank()) return
        _uiState.update { it.copy(isAnalyzing = true, aiAnalysisResult = "🤖 AI分析中...") }

        viewModelScope.launch(Dispatchers.IO) {
            val lang = _uiState.value.currentLang
            val langName = LANGUAGES.find { it.code == lang }?.name ?: lang
            val config = aiConfigStore.config.first()

            // 使用增强的分析功能
            val result = aiService.analyzeSentence(config, sentence, langName)
            _uiState.update { it.copy(
                isAnalyzing = false,
                aiAnalysisResult = result ?: "AI未配置或请求失败，请在设置中配置API Key"
            )}
        }
    }

    /**
     * 修复当前句子的转录错误
     */
    fun fixTranscription() {
        val sentence = _uiState.value.currentSentence
        if (sentence.isBlank()) return
        _uiState.update { it.copy(isAnalyzing = true, aiAnalysisResult = "🔧 修复中...") }

        viewModelScope.launch(Dispatchers.IO) {
            val lang = _uiState.value.currentLang
            val langName = LANGUAGES.find { it.code == lang }?.name ?: lang
            val config = aiConfigStore.config.first()

            val result = aiService.fixTranscription(config, sentence, langName)
            _uiState.update { it.copy(
                isAnalyzing = false,
                aiAnalysisResult = result ?: "修复失败，请检查 AI 配置"
            )}
        }
    }

    /**
     * 生成学习笔记（基于当前字幕）
     */
    fun generateStudyNotes() {
        val sentences = _uiState.value.subtitles.take(10).map { it.text }
        if (sentences.isEmpty()) return
        _uiState.update { it.copy(isAnalyzing = true, aiAnalysisResult = "📝 生成笔记中...") }

        viewModelScope.launch(Dispatchers.IO) {
            val lang = _uiState.value.currentLang
            val langName = LANGUAGES.find { it.code == lang }?.name ?: lang
            val config = aiConfigStore.config.first()

            val result = aiService.generateStudyNotes(config, sentences, langName)
            _uiState.update { it.copy(
                isAnalyzing = false,
                aiAnalysisResult = result ?: "生成失败，请检查 AI 配置"
            )}
        }
    }

    /** Favorite operations */
    suspend fun isFavorite(word: String): Boolean {
        return favoriteRepository.isFavorite(word, _uiState.value.currentLang)
    }

    fun toggleFavorite(word: String, phonetic: String = "", translation: String = "") {
        android.util.Log.d("PlayerViewModel", "toggleFavorite: word=$word, lang=${_uiState.value.currentLang}")
        viewModelScope.launch {
            val lang = _uiState.value.currentLang
            val isFav = favoriteRepository.isFavorite(word, lang)
            android.util.Log.d("PlayerViewModel", "isFavorite: $isFav")
            if (isFav) {
                favoriteRepository.remove(word, lang)
                android.util.Log.d("PlayerViewModel", "Removed from favorites")
            } else {
                favoriteRepository.add(word, lang, phonetic, translation, _uiState.value.currentSentence)
                android.util.Log.d("PlayerViewModel", "Added to favorites")
            }
        }
    }

    /** TTS */
    fun speak(text: String) {
        tts?.speak(text, TextToSpeech.QUEUE_FLUSH, null, "word_tts")
    }

    /** Dictation */
    fun nextDictation() {
        val nextIdx = (_uiState.value.dictationIndex + 1).coerceAtMost(_uiState.value.subtitles.size - 1)
        _uiState.update { it.copy(dictationIndex = nextIdx) }
    }

    /** Get aligned word timings for current cue */
    fun getAlignedTimings(words: List<String>): List<WordTimestamp?> {
        val state = _uiState.value
        val cueIdx = state.currentCueIndex
        if (cueIdx < 0 || cueIdx >= state.subtitles.size || state.wordTimings.isEmpty()) {
            return List(words.size) { null }
        }
        val cue = state.subtitles[cueIdx]
        return WordAligner.alignWords(words, state.wordTimings, cue.startMs / 1000.0, cue.endMs / 1000.0)
    }

    /** Format remaining time for display */
    private fun formatRemainingTime(seconds: Long): String {
        return when {
            seconds < 60 -> "${seconds}秒"
            seconds < 3600 -> "${seconds / 60}分${seconds % 60}秒"
            else -> "${seconds / 3600}小时${(seconds % 3600) / 60}分"
        }
    }

    override fun onCleared() {
        tts?.shutdown()
        super.onCleared()
    }
}

