                "en", "english" -> "英语"
                "es", "spanish" -> "西班牙语"
                "fr", "french" -> "法语"
                "de", "german" -> "德语"
                "it", "italian" -> "意大利语"
                "pt", "portuguese" -> "葡萄牙语"
                "ru", "russian" -> "俄语"
                "ja", "japanese" -> "日语"
                "ko", "korean" -> "韩语"
                "ar", "arabic" -> "阿拉伯语"
                "th", "thai" -> "泰语"
                "vi", "vietnamese" -> "越南语"
                else -> "英语"
